{
  args: {
    ...defaultArgs,
    asChild: true,
    gap: "sm",
    align: "center"
  },
  render: args => <StorySection title="As child" description="Style a single child element (e.g., list) while preserving semantics.">
      <Flex {...args}>
        <ul style={{
        listStyle: "none",
        padding: 0,
        margin: 0
      }}>
          {["First", "Second", "Third"].map(item => <li key={item}>
              <DemoItem label={item} />
            </li>)}
        </ul>
      </Flex>
    </StorySection>
}
